/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Use ParlayLib to compute in parallel.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
void solveLinearSystem(parlay::sequence<double> const& A, parlay::sequence<double> const& b, parlay::sequence<double> &x, size_t N) {

translation_src_example:
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Use OpenMP to compute in parallel.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
void solveLinearSystem(std::vector<double> const& A, std::vector<double> const& b, std::vector<double> &x, size_t N) {

    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    for (size_t k = 0; k < N; ++k) {
        #pragma omp parallel for
        for (size_t i = k + 1; i < N; ++i) {
            double factor = A_copy[i*N + k] / A_copy[k*N + k];
            for (size_t j = k; j < N; ++j) {
                A_copy[i*N + j] -= factor * A_copy[k*N + j];
            }
            b_copy[i] -= factor * b_copy[k];
        }
    }

    x[N - 1] = b_copy[N - 1] / A_copy[(N - 1) * N + (N - 1)];

    for (int i = N - 2; i >= 0; --i) {
        double sum = 0.0;
        #pragma omp parallel for reduction(+:sum)
        for (size_t j = i + 1; j < N; ++j) {
            sum += A_copy[i*N + j] * x[j];
        }
        x[i] = (b_copy[i] - sum) / A_copy[i*N + i];
    }
}

