    #pragma omp parallel for
    for (size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }

    fft(x);

    #pragma omp parallel for
    for (size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]) / static_cast<double>(N);
    }
}

