   output: r: [4, 1, 0, 1, 0, 1, 0, 1] i: [0, -2.41421, 0, -0.414214, 0, 0.414214, 0, 2.41421]
*/
void fft(std::vector<std::complex<double>> const& x, std::vector<double> &r, std::vector<double> &i) {

#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>

const double PI = std::acos(-1.0);

    int N = x.size();

    if (N == 0) {
        r.clear();
        i.clear();
        return;
    }

    std::vector<std::complex<double>> working_x = x;

    int log2N = 0;
    while ((1 << log2N) < N) {
        log2N++;
    }

    for (int k = 0; k < N; ++k) {
        int rev = 0;
        for (int j = 0; j < log2N; ++j) {
            if ((k >> j) & 1) {
                rev |= (1 << (log2N - 1 - j));
            }
        }
        if (k < rev) {
            std::swap(working_x[k], working_x[rev]);
        }
    }

    for (int s = 1; s <= log2N; ++s) {
        int m = 1 << s;
        std::complex<double> wm = std::polar(1.0, -2 * PI / m);

        #pragma omp parallel for schedule(static)
        for (int k = 0; k < N; k += m) {
            std::complex<double> w = 1.0;
            for (int j = 0; j < m / 2; ++j) {
                std::complex<double> t = w * working_x[k + j + m / 2];
                std::complex<double> u = working_x[k + j];
                working_x[k + j] = u + t;
                working_x[k + j + m / 2] = u - t;
                w *= wm;
            }
        }
    }

    r.resize(N);
    i.resize(N);
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        r[k] = working_x[k].real();
        i[k] = working_x[k].imag();
    }
}

