/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
   Use OpenMP to compute in parallel.
   Example:

   input: [{0, 3}, {1, 1}, {2, 2}, {4, 4}, {0, 0}, {1, 2}, {3, 1}, {3, 3}]
   output: 13.4477
*/
double convexHullPerimeter(std::vector<Point> const& points) {

    if (points.size() < 3) {
        if (points.size() == 2) {
            return distance(points[0], points[1]);
        }
        return 0.0;
    }

    std::vector<Point> sorted_points = points;
    std::sort(sorted_points.begin(), sorted_points.end(), [](Point const& a, Point const& b) {
        if (a.x != b.x) {
            return a.x < b.x;
        }
        return a.y < b.y;
    });

    auto cross_product = [](Point const& o, Point const& a, Point const& b) {
        return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);
    };

    std::vector<Point> hull;
    hull.reserve(sorted_points.size() * 2);

    for (size_t i = 0; i < sorted_points.size(); ++i) {
        while (hull.size() >= 2 && cross_product(hull[hull.size()-2], hull.back(), sorted_points[i]) <= 0) {
            hull.pop_back();
        }
        hull.push_back(sorted_points[i]);
    }

    size_t upper_hull_size = hull.size();
    for (size_t i = sorted_points.size() - 2; i != (size_t)-1; --i) {
        while (hull.size() > upper_hull_size && cross_product(hull[hull.size()-2], hull.back(), sorted_points[i]) <= 0) {
            hull.pop_back();
        }
        hull.push_back(sorted_points[i]);
    }

    if (hull.size() > 1) {
        hull.pop_back();
    }

    double perimeter = 0.0;
    if (hull.empty()) {
        return 0.0;
    }

    #pragma omp parallel for reduction(+:perimeter)
    for (size_t i = 0; i < hull.size(); ++i) {
        perimeter += distance(hull[i], hull[(i + 1) % hull.size()]);
    }

    return perimeter;
}

