   output: 2
*/
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {

    std::vector<int> dist(N, -1);
    std::vector<int> current_level_nodes;

    dist[source] = 0;
    current_level_nodes.push_back(source);

    int level = 0;

    while (!current_level_nodes.empty()) {
        if (dist[dest] != -1) {
            return dist[dest];
        }

        std::vector<int> next_level_nodes;

        #pragma omp parallel
        {
            #pragma omp for nowait
            for (size_t i = 0; i < current_level_nodes.size(); ++i) {
                int u = current_level_nodes[i];

                for (size_t v = 0; v < N; ++v) {
                    if (A[u * N + v] == 1) {
