#include <omp.h>

/* Count the number of doubles in the vector x that have a fractional part 
   in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1). Store the counts in `bins`.
   Use OpenMP to compute in parallel.
   Examples:

   input: [7.8, 4.2, 9.1, 7.6, 0.27, 1.5, 3.8]
   output: [2, 1, 2, 2]

   input: [1.9, 0.2, 0.6, 10.1, 7.4]
   output: [2, 1, 1, 1]
*/
void countQuartiles(std::vector<double> const& x, std::array<size_t, 4> &bins) {

    bins.fill(0);

    int num_threads = 0;
    #pragma omp parallel
    {
        #pragma omp master
        {
            num_threads = omp_get_num_threads();
        }
    }

    std::vector<std::array<size_t, 4>> thread_local_bins(num_threads);
    for (int i = 0; i < num_threads; ++i) {
        thread_local_bins[i].fill(0);
    }

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::array<size_t, 4>& my_bins = thread_local_bins[tid];

        #pragma omp for nowait
        for (size_t i = 0; i < x.size(); ++i) {
            double val = x[i];
            double frac_part = fmod(val, 1.0);
            if (frac_part < 0) {
                frac_part += 1.0;
            }

            int bin_idx = static_cast<int>(frac_part * 4.0);
            my_bins[bin_idx]++;
        }
    }

    for (int i = 0; i < num_threads; ++i) {
        for (int j = 0; j < 4; ++j) {
            bins[j] += thread_local_bins[i][j];
        }
    }
}

