/* Compute the prefix sum of the vector x into output.
   Use OpenMP to compute in parallel.
   Example:

   input: [1, 7, 4, 6, 6, 2]
   output: [1, 8, 12, 18, 24, 26]
*/
void prefixSum(std::vector<double> const& x, std::vector<double> &output) {

    std::size_t n = x.size();
    if (n == 0) {
        output.clear();
        return;
    }

    output.resize(n);

    int num_threads;
    #pragma omp parallel
    {
        #pragma omp master
        {
            num_threads = omp_get_num_threads();
        }
    }

    std::vector<double> chunk_sums(num_threads);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();

        std::size_t chunk_size = (n + num_threads - 1) / num_threads;
        std::size_t start_idx = tid * chunk_size;
        std::size_t end_idx = std::min(start_idx + chunk_size, n);

        if (start_idx < end_idx) {
            output[start_idx] = x[start_idx];
            for (std::size_t i = start_idx + 1; i < end_idx; ++i) {
                output[i] = output[i - 1] + x[i];
            }
            chunk_sums[tid] = output[end_idx - 1];
        } else {
            chunk_sums[tid] = 0.0;
        }
    }

    for (int i = 1; i < num_threads; ++i) {
        chunk_sums[i] += chunk_sums[i - 1];
    }

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();

        std::size_t chunk_size = (n + num_threads - 1) / num_threads;
        std::size_t start_idx = tid * chunk_size;
        std::size_t end_idx = std::min(start_idx + chunk_size, n);

        double offset = (tid == 0) ? 0.0 : chunk_sums[tid - 1];

        for (std::size_t i = start_idx; i < end_idx; ++i) {
            output[i] += offset;
        }
    }
}

