/* Compute the reverse prefix sum of the vector x into output.
   Use OpenMP to compute in parallel.
   Examples:

   input: [1, 7, 4, 6, 6, 2]
   output: [2, 8, 14, 18, 25, 26]

   input: [3, 3, 7, 1, -2]
   output: [-2, -1, 6, 9, 12]
*/
void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {

    int N = x.size();
    if (N == 0) {
        output.clear();
        return;
    }

    output.resize(N);

    std::vector<int> y(N);
    #pragma omp parallel for
    for (int i = 0; i < N; ++i) {
        y[i] = x[N - 1 - i];
    }

    int num_threads;
    #pragma omp parallel
    {
        #pragma omp master
        {
            num_threads = omp_get_num_threads();
        }
    }

    std::vector<int> block_sums(num_threads);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int chunk_size = (N + num_threads - 1) / num_threads;
        int start_idx = tid * chunk_size;
        int end_idx = std::min((tid + 1) * chunk_size, N);

        if (start_idx < end_idx) {
            output[start_idx] = y[start_idx];
            for (int i = start_idx + 1; i < end_idx; ++i) {
                output[i] = output[i-1] + y[i];
            }
            block_sums[tid] = output[end_idx - 1];
        } else {
            block_sums[tid] = 0;
        }
    }

    for (int i = 1; i < num_threads; ++i) {
        block_sums[i] += block_sums[i-1];
    }

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        int chunk_size = (N + num_threads - 1) / num_threads;
        int start_idx = tid * chunk_size;
        int end_idx = std::min((tid + 1) * chunk_size, N);

        if (tid > 0 && start_idx < end_idx) {
            int offset = block_sums[tid - 1];
            for (int i = start_idx; i < end_idx; ++i) {
                output[i] += offset;
            }
        }
