translation_src_example:
#include <omp.h>

/* Sort the vector x of complex numbers by their magnitude in ascending order.
   Use OpenMP to sort in parallel.
   Example:

   input: [3.0-1.0i, 4.5+2.1i, 0.0-1.0i, 1.0-0.0i, 0.5+0.5i]
   output: [0.5+0.5i, 0.0-1.0i, 1.0-0.0i, 3.0-1.0i, 4.5+2.1i]
*/
void sortComplexByMagnitude(std::vector<std::complex<double>> &x) {

    int n = x.size();
    if (n <= 1) {
        return;
    }

    int num_threads_actual = omp_get_max_threads();
    if (num_threads_actual == 0) {
        num_threads_actual = 1;
    }

    if (n < 1024) {
        std::sort(x.begin(), x.end(), [](const std::complex<double>& a, const std::complex<double>& b) { return std::abs(a) < std::abs(b); });
        return;
    }

    int chunk_size = (n + num_threads_actual - 1) / num_threads_actual;

    #pragma omp parallel for
    for (int i = 0; i < num_threads_actual; ++i) {
        int start_idx = i * chunk_size;
        int end_idx = std::min((i + 1) * chunk_size, n);
        if (start_idx < end_idx) {
            std::sort(x.begin() + start_idx, x.begin() + end_idx, [](const std::complex<double>& a, const std::complex<double>& b) { return std::abs(a) < std::abs(b); });
        }
    }

    for (int current_size = chunk_size; current_size < n; current_size *= 2) {
        #pragma omp parallel for
        for (int left_start = 0; left_start < n; left_start += 2 * current_size) {
            int mid = std::min(left_start + current_size - 1, n - 1);
            int right_end = std::min(left_start + 2 * current_size - 1, n - 1);

            if (mid < right_end) {
                std::inplace_merge(x.begin() + left_start, x.begin() + mid + 1, x.begin() + right_end + 1, [](const std::complex<double>& a, const std::complex<double>& b) { return std::abs(a) < std::abs(b); });
            }
        }
    }
}

