   output: [4, 0, 1, 2, 3]
*/
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks) {

    size_t n = x.size();
    ranks.resize(n);

    if (n == 0) {
        return;
    }

    std::vector<std::pair<float, size_t>> elements(n);

    #pragma omp parallel for
    for (size_t i = 0; i < n; ++i) {
        elements[i] = {x[i], i};
    }

    std::sort(elements.begin(), elements.end(), [](const std::pair<float, size_t>& a, const std::pair<float, size_t>& b) {
        if (a.first != b.first) {
            return a.first < b.first;
        }
        return a.second < b.second;
    });

    #pragma omp parallel for
    for (size_t i = 0; i < n; ++i) {
        ranks[elements[i].second] = i;
    }
}

