   int startTime, duration;
   float value;
};

/* Sort vector of Result structs by start time in ascending order.
   Use OpenMP to sort in parallel.
   Example:

   input: [{startTime=8, duration=4, value=-1.22}, {startTime=2, duration=10, value=1.0}, {startTime=10, duration=3, value=0.0}]
   output: [{startTime=2, duration=10, value=1.0}, {startTime=8, duration=4, value=-1.22}, {startTime=10, duration=3, value=0.0}]
*/
void sortByStartTime(std::vector<Result> &results) {

    if (results.empty()) {
        return;
    }

    std::vector<Result> temp_buffer(results.size());

    auto parallelMergeSortRecursive = 
        [&](auto self, int left, int right) -> void {
        if (left >= right) {
            return;
        }

        const int THRESHOLD = 2048; 
        if (right - left + 1 <= THRESHOLD) {
            std::sort(results.begin() + left, results.begin() + right + 1, [](const Result& a, const Result& b) {
                return a.startTime < b.startTime;
            });
            return;
        }

        int mid = left + (right - left) / 2;

        #pragma omp task shared(results, temp_buffer)
        self(self, left, mid);
        #pragma omp task shared(results, temp_buffer)
        self(self, mid + 1, right);

        #pragma omp taskwait

        for (int i = left; i <= mid; ++i) {
            temp_buffer[i] = results[i];
        }
        for (int i = mid + 1; i <= right; ++i) {
            temp_buffer[i] = results[i];
        }

        int i = left;       
        int j = mid + 1;    
        int k = left;       

        while (i <= mid && j <= right) {
            if (temp_buffer[i].startTime < temp_buffer[j].startTime) {
                results[k++] = temp_buffer[i++];
            } else {
                results[k++] = temp_buffer[j++];
            }
        }

        while (i <= mid) {
            results[k++] = temp_buffer[i++];
        }

        while (j <= right) {
            results[k++] = temp_buffer[j++];
        }
    };

    #pragma omp parallel
    {
        #pragma omp single nowait
        {
            parallelMergeSortRecursive(parallelMergeSortRecursive, 0, results.size() - 1);
        }
    }
}

