/* Sort the vector x in ascending order ignoring elements with value 0.
   Leave zero valued elements in-place. 
	 Use OpenMP to sort x in parallel. 
   Example:

   input: [8, 4, 0, 9, 8, 0, 1, -1, 7]
   output: [-1, 1, 0, 4, 7, 0, 8, 8, 9]
*/
void sortIgnoreZero(std::vector<int> &x) {

    std::vector<int> nonZeroValues;
    std::vector<size_t> nonZeroIndices;

    for (size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0) {
            nonZeroValues.push_back(x[i]);
            nonZeroIndices.push_back(i);
        }
    }

    int n = nonZeroValues.size();

    if (n == 0) {
        return;
    }

    for (int phase = 0; phase < n; ++phase) {
        #pragma omp parallel for
        for (int i = 1; i < n - 1; i += 2) {
            if (nonZeroValues[i] > nonZeroValues[i+1]) {
                std::swap(nonZeroValues[i], nonZeroValues[i+1]);
            }
        }

        #pragma omp parallel for
        for (int i = 0; i < n - 1; i += 2) {
            if (nonZeroValues[i] > nonZeroValues[i+1]) {
                std::swap(nonZeroValues[i], nonZeroValues[i+1]);
            }
        }
    }

    #pragma omp parallel for
    for (size_t i = 0; i < nonZeroValues.size(); ++i) {
        x[nonZeroIndices[i]] = nonZeroValues[i];
    }
}

