void solveLinearSystem(parlay::sequence<COOElement> const& A, parlay::sequence<double> const& b, parlay::sequence<double> &x, size_t N) {

translation_src_example:
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Use OpenMP to compute in parallel.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(std::vector<COOElement> const& A, std::vector<double> const& b, std::vector<double> &x, size_t N) {

    std::vector<double> diag_A(N);
    std::vector<std::vector<std::pair<size_t, double>>> off_diag_A(N);

    for (const auto& elem : A) {
        if (elem.row == elem.column) {
            diag_A[elem.row] = elem.value;
        } else {
            off_diag_A[elem.row].push_back({elem.column, elem.value});
        }
    }

    std::vector<double> x_new(N);
    x = b; 

    double tolerance = 1e-6;
    int max_iterations = 1000;

    for (int iter = 0; iter < max_iterations; ++iter) {
        #pragma omp parallel for
        for (size_t i = 0; i < N; ++i) {
            double sum_off_diag = 0.0;
            for (const auto& off_elem : off_diag_A[i]) {
                sum_off_diag += off_elem.second * x[off_elem.first];
            }
            x_new[i] = (b[i] - sum_off_diag) / diag_A[i];
        }

        double current_residual_norm_sq = 0.0;
        #pragma omp parallel for reduction(+:current_residual_norm_sq)
        for (size_t i = 0; i < N; ++i) {
            double Ax_i = diag_A[i] * x_new[i];
            for (const auto& off_elem : off_diag_A[i]) {
                Ax_i += off_elem.second * x_new[off_elem.first];
            }
            double residual_i = Ax_i - b[i];
            current_residual_norm_sq += residual_i * residual_i;
        }
        double current_residual_norm = std::sqrt(current_residual_norm_sq);

        x = x_new;

        if (current_residual_norm < tolerance) {
            break;
        }
    }
}

