/* Compute the matrix multiplication Y=AX. A is a sparse MxK matrix in COO format.
   X is a sparse KxN matrix in COO format. Y is a dense MxN matrix in row-major.
   Use OpenMP to compute in parallel.
   Example:

   input: A=[{0,0,-2}, {0,1,1}, {1,1,-1}] X=[{0,1,2}, {1,0,-1}]
   output: Y=[{-1,-4}, {1,0}]
*/
void spmm(std::vector<COOElement> const& A, std::vector<COOElement> const& X, std::vector<double> &Y, size_t M, size_t K, size_t N) {

    Y.assign(M * N, 0.0);

    std::vector<std::vector<COOElement>> X_by_row(K);
    for (const auto& x_elem : X) {
        X_by_row[x_elem.row].push_back(x_elem);
    }

    int num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> Y_private(num_threads, std::vector<double>(M * N, 0.0));

    #pragma omp parallel for
    for (size_t i_A = 0; i_A < A.size(); ++i_A) {
        const auto& a_elem = A[i_A];
        size_t row_A = a_elem.row;
        size_t col_A = a_elem.column;
        double val_A = a_elem.value;

        int tid = omp_get_thread_num();

        for (const auto& x_elem : X_by_row[col_A]) {
            size_t col_X = x_elem.column;
            double val_X = x_elem.value;

            Y_private[tid][row_A * N + col_X] += val_A * val_X;
        }
    }

    for (int tid = 0; tid < num_threads; ++tid) {
        for (size_t idx = 0; idx < M * N; ++idx) {
            Y[idx] += Y_private[tid][idx];
        }
    }
}

