   Example:

   input: A=[{0,0,4}, {0,1,3}, {1,0,6}, {1,1,3}]
   output: L=[{0,0,1},{1,0,1.5}, {1,1,1}] U=[{0,0,4}, {0,1,3}, {1,1,-1.5}]
*/
void luFactorize(std::vector<COOElement> const& A, std::vector<double> &L, std::vector<double> &U, size_t N) {

    std::vector<double> matA(N * N, 0.0);
    for (const auto& elem : A) {
        matA[elem.row * N + elem.column] = elem.value;
    }

    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    for (size_t i = 0; i < N; ++i) {
        L[i * N + i] = 1.0;
    }

    for (size_t k = 0; k < N; ++k) {
        double sum_ukk = 0.0;
        for (size_t p = 0; p < k; ++p) {
            sum_ukk += L[k * N + p] * U[p * N + k];
        }
        U[k * N + k] = matA[k * N + k] - sum_ukk;

        #pragma omp parallel for
        for (size_t i = k + 1; i < N; ++i) {
            double sum_lik = 0.0;
            for (size_t p = 0; p < k; ++p) {
                sum_lik += L[i * N + p] * U[p * N + k];
            }
            L[i * N + k] = (matA[i * N + k] - sum_lik) / U[k * N + k];
        }

        #pragma omp parallel for
        for (size_t j = k + 1; j < N; ++j) {
            double sum_ukj = 0.0;
            for (size_t p = 0; p < k; ++p) {
                sum_ukj += L[k * N + p] * U[p * N + j];
            }
            U[k * N + j] = matA[k * N + j] - sum_ukj;
        }
    }
